#include <Wire.h>
#include <SparkFun_ADXL345.h>

extern float miners_rule_damage_per_cycle(float amplitude_g,float C_log10,float m);

SPARKFUN_ADXL345 accel;
const int STRAIN_PIN=A0,ESP_TX=3,ESP_RX=4;
const float C_LOG=12.0f,M_EXP=3.0f,D_ALARM=0.8f;
float cumulative_D=0.0f;
long total_cycles=0;

// === Accelerometer ===
void accel_init(){Wire.begin();accel.begin();accel.setRangeSetting(16);accel.setRate(100);}
float accel_peak(){
  float pk=0;
  unsigned long t=millis();
  while(millis()-t<1000){int x,y,z;accel.readAccel(&x,&y,&z);float a=abs(z)/64.0f;if(a>pk)pk=a;}
  return pk;}

// === Strain Gauge ===
void strain_init(){pinMode(STRAIN_PIN,INPUT);}
float strain_read(){return (analogRead(STRAIN_PIN)-512)*2000.0f/512.0f;}

// === FRAM Storage ===
void fram_init(){/* I2C FRAM at 0x50 */}
void fram_save(float d,long c){Wire.beginTransmission(0x50);Wire.write(0x00);Wire.write(0x00);uint32_t di;memcpy(&di,&d,4);Wire.write((di>>24)&0xFF);Wire.write((di>>16)&0xFF);Wire.write((di>>8)&0xFF);Wire.write(di&0xFF);Wire.endTransmission();}
float fram_load(){Wire.beginTransmission(0x50);Wire.write(0x00);Wire.write(0x00);Wire.endTransmission(false);Wire.requestFrom(0x50,4);uint32_t v=((uint32_t)Wire.read()<<24)|((uint32_t)Wire.read()<<16)|((uint32_t)Wire.read()<<8)|Wire.read();float d;memcpy(&d,&v,4);return(d>0&&d<2)?d:0;}

// === Telemetry ===
void telemetry_send(float d,bool alarm){Serial1.print("{\"D\":");Serial1.print(d,5);Serial1.print(",\"life_pct\":");Serial1.print((1.0f-d)*100,1);Serial1.print(",\"alarm\":");Serial1.print(alarm?"true":"false");Serial1.println("}");}

// === Fault Handler ===
bool fault_check(){if(!accel.isConnected()){Serial.println("FAULT:ACCEL");return true;}return false;}

void setup(){
  Serial.begin(115200);Serial1.begin(9600);
  accel_init();strain_init();fram_init();
  cumulative_D=fram_load();
  Serial.print("Loaded D=");Serial.println(cumulative_D,4);
}

unsigned long lastLog=0;
void loop(){
  if(fault_check())return;
  float pk=accel_peak();
  float d_inc=miners_rule_damage_per_cycle(pk,C_LOG,M_EXP);
  cumulative_D+=d_inc;total_cycles++;
  unsigned long now=millis();
  if(now-lastLog>=60000){
    lastLog=now;
    fram_save(cumulative_D,total_cycles);
    bool alarm=(cumulative_D>=D_ALARM);
    telemetry_send(cumulative_D,alarm);
    if(alarm)Serial.println("ALARM:FATIGUE_D0.8");
    Serial.print("D=");Serial.print(cumulative_D,5);Serial.print(" cyc=");Serial.println(total_cycles);
  }
}
